mapper.select:
SELECT p.order_id AS orderId, u.name AS memberName, LOWER(m.type) AS membershipType, m.type_rep AS typeRep, tu.name AS trainerName, p.payment_date AS paymentDate, p.payment_price AS paymentPrice, p.payment_fee AS paymentFee, (p.payment_price - p.payment_fee) AS netPrice, p.status AS status, p.canceled_at AS canceledAt, p.reason AS reason, mp.start_date AS startDate FROM PAYMENT p JOIN MEMBERSHIP m ON p.membership_id = m.id JOIN `USER` u ON p.user_id = u.id LEFT JOIN TRAINER t ON m.trainer_id = t.id LEFT JOIN `USER` tu ON t.user_id = tu.id LEFT JOIN MEMBERSHIP_PT mp ON p.mp_id = mp.id WHERE m.gym_id = #{gymNum}
AND DATE(p.payment_date) >= #{startDate}
AND DATE(p.payment_date) <= #{endDate}
AND LOWER(m.type) = #{membershipType}
AND t.id = #{trainerId}
AND p.status = #{status}
AND u.name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY p.payment_date DESC LIMIT #{startRow}, #{pageSize}

SELECT COUNT(*)
FROM PAYMENT p
JOIN MEMBERSHIP m
  ON p.membership_id = m.id
JOIN `USER` u
  ON p.user_id = u.id
LEFT JOIN TRAINER t
  ON m.trainer_id = t.id
WHERE m.gym_id = #{gymNum}


    AND DATE(p.payment_date) >= #{startDate}



    AND DATE(p.payment_date) <= #{endDate}



    AND LOWER(m.type) = #{membershipType}



    AND t.id = #{trainerId}



    AND p.status = #{status}



    AND u.name LIKE CONCAT('%', #{keyword}, '%')

SELECT IFNULL(SUM(p.payment_price), 0) AS totalSales, IFNULL(SUM(CASE WHEN m.type IN ('day','month') THEN p.payment_price ELSE 0 END), 0) AS gymSales, IFNULL(SUM(CASE WHEN m.type = 'pt' THEN p.payment_price ELSE 0 END), 0) AS ptSales, IFNULL(SUM(p.payment_fee), 0) AS totalFee, IFNULL(SUM(p.payment_price - p.payment_fee), 0) AS netSales, 0 AS growthRate FROM PAYMENT p JOIN MEMBERSHIP m ON p.membership_id = m.id WHERE m.gym_id = #{gymNum} AND p.status = '결제완료'
AND DATE(p.payment_date) >= #{startDate}
AND DATE(p.payment_date) <= #{endDate}
AND LOWER(m.type) = #{membershipType}
AND m.trainer_id = #{trainerId}
